이 프로젝트는 설정 파일과 가이드 문서만 있는 템플릿 구조입니다. 실제 팔로우 관련 코드가 없으므로, JPA/QueryDSL 쿼리 최적화에 대한 **모범 사례 기반의 실제 구현 예제**를 제공하겠습니다.

프로젝트의 스타일과 가이드라인에 맞춘 팔로우 목록 조회 최적화 코드를 생성하겠습니다.

## 분석 및 최적화 전략

### 1. Entity 정의

프로젝트 컨벤션에 맞춘 Follow Entity:

```kotlin
// domain/src/main/kotlin/com/maum/backend/entity/follow/FollowEntity.kt
@Entity
@Table(catalog = "maum", name = "follow", indexes = [
    Index(name = "idx_follower_id", columnList = "follower_id"),
    Index(name = "idx_followed_id", columnList = "followed_id"),
    Index(name = "idx_follower_followed", columnList = "follower_id,followed_id", unique = true),
    Index(name = "idx_created_at", columnList = "created_at")
])
class FollowEntity(
    @Id
    @GeneratedValue(generator = "uuid2")
    @GenericGenerator(name = "uuid2", strategy = "uuid2")
    val id: String = "",

    @Column(name = "follower_id", nullable = false)
    val followerId: String,

    @Column(name = "followed_id", nullable = false)
    val followedId: String,

    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "follower_id", referencedColumnName = "id", insertable = false, updatable = false)
    val follower: UserEntity? = null,

    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "followed_id", referencedColumnName = "id", insertable = false, updatable = false)
    val followed: UserEntity? = null,

    @CreatedDate
    @Column(columnDefinition = "datetime(3)", nullable = false, updatable = false)
    var createdAt: LocalDateTime = LocalDateTime.now(),

    @LastModifiedDate
    var updatedAt: LocalDateTime = LocalDateTime.now(),
)
```

### 2. Repository 최적화

```kotlin
// domain/src/main/kotlin/com/maum/backend/repository/follow/FollowRepository.kt
interface FollowRepository : JpaRepository<FollowEntity, String>, FollowRepositoryCustom {

    // 기본 메서드 (fetch join 없음)
    fun countByFollowerId(followerId: String): Long

    fun existsByFollowerIdAndFollowedId(followerId: String, followedId: String): Boolean

    fun deleteByFollowerIdAndFollowedId(followerId: String, followedId: String)
}

// QueryDSL 커스텀 인터페이스
interface FollowRepositoryCustom {

    // 1. Pagination이 있는 팔로우 목록 조회 (최적화)
    fun findFollowingList(
        followerId: String,
        pageable: Pageable
    ): Page<FollowEntity>

    // 2. Projection을 이용한 가벼운 조회
    fun findFollowingListProjection(
        followerId: String,
        pageable: Pageable
    ): Page<FollowUserDto>

    // 3. 팔로워 목록 조회
    fun findFollowerList(
        followedId: String,
        pageable: Pageable
    ): Page<FollowEntity>
}
```

### 3. QueryDSL 구현 (최적화된 쿼리)

```kotlin
// domain/src/main/kotlin/com/maum/backend/repository/follow/FollowRepositoryImpl.kt
@Repository
class FollowRepositoryImpl(
    private val queryFactory: JPAQueryFactory,
) : FollowRepositoryCustom {

    private val follow = QFollowEntity.followEntity
    private val followedUser = QUserEntity.userEntity

    override fun findFollowingList(
        followerId: String,
        pageable: Pageable
    ): Page<FollowEntity> {
        // fetch join을 통한 N+1 해결
        val content = queryFactory
            .selectFrom(follow)
            .leftJoin(follow.followed).fetchJoin()
            .where(follow.followerId.eq(followerId))
            .orderBy(follow.createdAt.desc())
            .offset(pageable.offset)
            .limit(pageable.pageSize.toLong())
            .fetch()

        val total = queryFactory
            .select(follow.count())
            .from(follow)
            .where(follow.followerId.eq(followerId))
            .fetchOne() ?: 0L

        return PageImpl(content, pageable, total)
    }

    override fun findFollowingListProjection(
        followerId: String,
        pageable: Pageable
    ): Page<FollowUserDto> {
        // Projection을 사용한 더욱 경량화된 조회
        val content = queryFactory
            .select(
                Projections.constructor(
                    FollowUserDto::class.java,
                    follow.id,
                    follow.followedId,
                    followedUser.id,
                    followedUser.nickname,
                    followedUser.profileImageUrl,
                    followedUser.status,
                    follow.createdAt
                )
            )
            .from(follow)
            .leftJoin(follow.followed, followedUser)
            .where(follow.followerId.eq(followerId))
            .orderBy(follow.createdAt.desc())
            .offset(pageable.offset)
            .limit(pageable.pageSize.toLong())
            .fetch()

        val total = queryFactory
            .select(follow.count())
            .from(follow)
            .where(follow.followerId.eq(followerId))
            .fetchOne() ?: 0L

        return PageImpl(content, pageable, total)
    }

    override fun findFollowerList(
        followedId: String,
        pageable: Pageable
    ): Page<FollowEntity> {
        val content = queryFactory
            .selectFrom(follow)
            .leftJoin(follow.follower).fetchJoin()
            .where(follow.followedId.eq(followedId))
            .orderBy(follow.createdAt.desc())
            .offset(pageable.offset)
            .limit(pageable.pageSize.toLong())
            .fetch()

        val total = queryFactory
            .select(follow.count())
            .from(follow)
            .where(follow.followedId.eq(followedId))
            .fetchOne() ?: 0L

        return PageImpl(content, pageable, total)
    }
}
```

### 4. DTO 정의

```kotlin
// api/src/main/kotlin/com/maum/backend/dto/follow/FollowUserDto.kt
data class FollowUserDto(
    val followId: String,
    val userId: String,
    val targetUserId: String,
    val targetUserNickname: String,
    val targetUserProfileImageUrl: String,
    val targetUserStatus: String,
    val followedAt: LocalDateTime
)
```

## 성능 최적화 요약

| 항목 | 문제점 | 해결책 |
|------|-------|-------|
| **N+1 쿼리** | 팔로우 목록 조회 후 각 사용자 정보 개별 조회 | `leftJoin().fetchJoin()` 사용 |
| **불필요한 필드** | 팔로우 목록에서 모든 User 정보 조회 | `Projection` 사용으로 필요한 필드만 조회 |
| **인덱스 누락** | follower_id, followed_id 조회 시 성능 저하 | 3개의 인덱스 추가 |
| **페이지네이션** | 대량 데이터 조회 시 메모리 과다 사용 | offset/limit 적용 |
| **COUNT 최적화** | 페이지 수 계산을 위한 별도 COUNT 쿼리 | 필요시 Redis 캐싱 고려 |

## 권장 사항

1. **일반적인 경우**: `findFollowingListProjection()` 사용 - 필요한 정보만 조회
2. **전체 Entity 필요**: `findFollowingList()` - fetch join으로 관계 데이터 로드
3. **대규모 팔로우**: Redis에 TOP 팔로워/팔로잉 캐싱
4. **인덱스**: Unique 인덱스로 중복 팔로우 방지

파일 위치:
- Entity: `/domain/src/main/kotlin/com/maum/backend/entity/follow/FollowEntity.kt`
- Repository: `/domain/src/main/kotlin/com/maum/backend/repository/follow/FollowRepository.kt`
- 구현체: `/domain/src/main/kotlin/com/maum/backend/repository/follow/FollowRepositoryImpl.kt`
- DTO: `/api/src/main/kotlin/com/maum/backend/dto/follow/FollowUserDto.kt`

